module priority_encoder (
    input [3:0] in,
    output reg [1:0] neg
);

    always @(*) begin
        if (in[3])
            neg = 2'b11;
        else if (in[2])
            neg = 2'b10;
        else if (in[1])
            neg = 2'b01;
        else
            neg = 2'b00;
    end

endmodule
